#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<int>seq(n);for(auto&x:seq)scanf("%d",&x);stack<int>st;int cur=1,idx=0;string out;bool ok=true;while(idx<n){if(st.empty()||st.top()<seq[idx]){if(cur>n){ok=false;break;}st.push(cur++);out+="+\n";}else if(st.top()==seq[idx]){st.pop();out+="-\n";idx++;}else{ok=false;break;}}if(ok)printf("%s",out.c_str());else printf("NO\n");}
